module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);

reg [31:0] product;
reg [15:0] multiplier;
reg [4:0] counter;
reg done_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        product <= 0;
        multiplier <= 0;
        counter <= 0;
        done_reg <= 0;
    end
    else if (start) begin
        multiplier <= bin;
        product <= 0;
        counter <= 16;
        done_reg <= 0;
    end
    else if (counter > 0) begin
        if (multiplier[0]) begin
            product <= product + (ain << (16 - counter));
        end
        multiplier <= multiplier >> 1;
        counter <= counter - 1;
    end
    else begin
        done_reg <= 1;
    end
end

assign yout = product;
assign done = done_reg;

endmodule
